css_js_sketch:
:root{--fs-body:1rem; --lh-body:1.55; --fs-2nd:.96rem; --lh-2nd:1.5}
.f-explain,ul.remedy li,ul.plain li,.movement p.lead{font-size:var(--fs-body); line-height:var(--lh-body)}
.cite-gloss,.structural p,.sc-note{font-size:var(--fs-2nd); line-height:var(--lh-2nd)}
.f-explain p{margin:0 0 .85rem}  /* match .content-col p, line 126 */

[data-theme="dark"]{ --tx-2:var(--base-500); }  /* line 68 — 5.19:1 on --black, parity with light's 4.97:1 */
/* and either delete --tx-3 from both blocks or use it: */
ul.plain.dropped li::before{color:var(--tx-3)}

[data-theme="dark"]{
  --code-bg:var(--base-900);  /* 1.28:1 vs bg — parity with light's 1.24:1 */
  --hl-comment:#94928B;  /* 4.79:1 on base-900 */
  --hl-number:#9A8FD0;   /* 5.12:1 */
  --hl-builtin:#5E9ACB;  /* 4.94:1 */
}
